module binary_to_gray(
    input       [3:0]   gray_in     ,

    output  reg [3:0]   gray_out
);

   always @(*) begin
       gray_out[3] = gray_in[3];
       gray_out[2] = gray_in[3] ^ gray_in[2];
       gray_out[1] = gray_in[2] ^ gray_in[1];
       gray_out[0] = gray_in[1] ^ gray_in[0];
   end

endmodule
